                .with(DeserializationFeature.USE_BIG_DECIMAL_FOR_FLOATS)
                .readValue(json);

        assertEquals(w.typeEnum, w2.typeEnum);
        assertEquals(new BigDecimal(NUM_STR), (BigDecimal) w2.value);
    }"
    }
